    45→      opacity: 0.4;
    46→    }
    47→
    48→    @media ${breakpoints.M} {
    49→      padding: ${$withIcon ? '1rem' : $large ? '1.125rem 1.5rem' : '0.875rem 1.5rem'};
    50→    }
    51→  `
    52→)
    53→
    54→type DefaultProperties = {
    55→  /**
    56→   * Clear button styles leaving just a text
    57→   */
    58→  clear?: boolean
    59→  round?: boolean
    60→  /**
    61→   * Is the button large?
    62→   */
    63→  large?: boolean
    64→  /**
    65→   * Does the button have an icon?
    66→   */
    67→  icon?: IconName
    68→  /**
    69→   * Size of the icon
    70→   */
    71→  iconSize?: number
    72→  /**
    73→   * Is the button disabled?
    74→   */
    75→  disabled?: boolean
    76→  /**
    77→   * Does the button have an icon?
    78→   */
    79→  children?: string | React.ReactNode
    80→  /**
    81→   * Optional click handler
    82→   */
    83→  onClick?: () => void
    84→}
    85→
    86→// Remove StyledButton props from ButtonProps to avoid duplicate props
    87→type ButtonProperties = DefaultProperties &
    88→  Omit<React.ComponentProps<'button'>, keyof DefaultProperties>
    89→
    90→/**
    91→ * Primary UI component for user interaction
    92→ */
    93→export const Button: React.FC<React.PropsWithChildren<ButtonProperties>> = ({
    94→  children,
    95→  large = false,
    96→  clear = false,
    97→  round = false,
    98→  icon,
    99→  iconSize,
   100→  ...properties
   101→}: ButtonProperties) => {
   102→  const { color } = useTheme()
   103→
   104→  return (
   105→    <StyledButton
   106→      type="button"
   107→      $large={large}
   108→      $clear={clear}
   109→      $round={round}
